/**
 * Unit Tests for Final Decision Stage (T035c)
 *
 * Tests final label assignment and action determination logic following TDD approach.
 * These tests MUST FAIL initially before implementation.
 */

import { finalDecisionStage, FinalDecisionConfig, FinalDecisionResult } from '../../src/stages/final-decision';
import { EmailMessage, ClassificationSession } from '../../src/types';
import { FinalClassification } from '../../src/stages/ai-classification';

// Mock data factories
function createMockEmail(overrides: Partial<EmailMessage> = {}): EmailMessage {
  return {
    id: 'test-email-123',
    threadId: 'thread-123',
    from: {
      email: 'sender@example.com',
      name: 'Test Sender',
      raw: 'Test Sender <sender@example.com>',
    },
    to: [
      {
        email: 'recipient@example.com',
        name: 'Test Recipient',
        raw: 'Test Recipient <recipient@example.com>',
      },
    ],
    subject: 'Test Email',
    date: new Date('2025-01-15T10:00:00Z'),
    gmailLabels: ['INBOX', 'UNREAD'],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'From', value: 'sender@example.com' },
        { name: 'To', value: 'recipient@example.com' },
        { name: 'Subject', value: 'Test Email' },
      ],
    },
    isProcessed: false,
    processingPriority: 50,
    ...overrides,
  };
}

function createMockSession(overrides: Partial<ClassificationSession> = {}): ClassificationSession {
  return {
    id: 'session-123',
    startedAt: new Date('2025-01-15T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'sequential',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-config-v1',
    configSnapshot: {},
    errors: [],
    warnings: [],
    ...overrides,
  };
}

function createMockConfig(overrides: Partial<FinalDecisionConfig> = {}): FinalDecisionConfig {
  return {
    archiveThresholds: {
      low_importance: 0.3,
      medium_importance: 0.5,
      high_importance: 0.7,
    },
    defaultArchiveThreshold: 'low_importance',
    labelAssignmentRules: {
      maxLabels: 3,
      minSecondaryConfidence: 0.4,
      allowedCombinations: ['financial+actionable'],
    },
    actionDetermination: {
      archiveIfBelowThreshold: true,
      markAsReadIfArchived: false,
      applyCustomActions: true,
    },
    ...overrides,
  };
}

describe('Final Decision Stage (T035c)', () => {
  describe('Input Validation', () => {
    it('should throw error if email is missing id', async () => {
      const email = createMockEmail({ id: undefined as unknown as string });
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable'],
        confidence: 0.85,
        reasoning: 'Test reasoning',
      };

      await expect(finalDecisionStage(email, session, aiResult, config)).rejects.toThrow(
        'Invalid email input: id or gmail_id is required'
      );
    });

    it('should throw error if session is missing id', async () => {
      const email = createMockEmail();
      const session = createMockSession({ id: undefined as unknown as string });
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: [],
        confidence: 0.85,
        reasoning: 'Test reasoning',
      };

      await expect(finalDecisionStage(email, session, aiResult, config)).rejects.toThrow(
        'Invalid session input: id or session_id is required'
      );
    });

    it('should throw error if AI result is invalid', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult = null as unknown as FinalClassification;

      await expect(finalDecisionStage(email, session, aiResult, config)).rejects.toThrow('Invalid AI classification');
    });

    it('should throw error if config is missing', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: [],
        confidence: 0.85,
        reasoning: 'Test reasoning',
      };
      const config = null as unknown as FinalDecisionConfig;

      await expect(finalDecisionStage(email, session, aiResult, config)).rejects.toThrow('Configuration is required');
    });
  });

  describe('Label Assignment', () => {
    it('should assign primary category label correctly', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: [],
        confidence: 0.85,
        reasoning: 'High confidence financial email',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.assignedLabels.primary).toBe('financial');
      expect(result.assignedLabels.secondary).toEqual([]);
    });

    it('should assign secondary category labels correctly', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable', 'travel'],
        confidence: 0.85,
        reasoning: 'Multi-label classification',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.assignedLabels.primary).toBe('financial');
      expect(result.assignedLabels.secondary).toEqual(['actionable', 'travel']);
    });

    it('should limit secondary labels to maxLabels', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        labelAssignmentRules: {
          maxLabels: 2,
          minSecondaryConfidence: 0.3,
          allowedCombinations: [],
        },
      });
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable', 'travel', 'commerce', 'social'],
        confidence: 0.85,
        reasoning: 'Many categories',
        category_scores: {
          financial: 15,
          actionable: 12,
          travel: 10,
          commerce: 8,
          social: 6,
        },
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.assignedLabels.primary).toBe('financial');
      expect(result.assignedLabels.secondary.length).toBeLessThanOrEqual(1); // maxLabels = 2, minus primary = 1
    });

    it('should filter secondary labels by minSecondaryConfidence', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        labelAssignmentRules: {
          maxLabels: 3,
          minSecondaryConfidence: 0.6,
          allowedCombinations: [],
        },
      });
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable', 'travel'],
        confidence: 0.85,
        reasoning: 'Multi-label with varying confidence',
        category_scores: {
          financial: 15,
          actionable: 12, // 0.8 confidence (12/15)
          travel: 3, // 0.2 confidence (3/15)
        },
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.assignedLabels.primary).toBe('financial');
      // Only 'actionable' should pass minSecondaryConfidence threshold
      expect(result.assignedLabels.secondary).toEqual(['actionable']);
    });

    it('should validate allowed label combinations', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        labelAssignmentRules: {
          maxLabels: 3,
          minSecondaryConfidence: 0.3,
          allowedCombinations: ['financial+actionable'],
        },
      });
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable', 'social'],
        confidence: 0.85,
        reasoning: 'Multi-label classification',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.assignedLabels.primary).toBe('financial');
      // 'actionable' allowed with financial, but 'social' should be rejected
      expect(result.assignedLabels.secondary).toContain('actionable');
      expect(result.assignedLabels.secondary).not.toContain('social');
    });
  });

  describe('Action Determination', () => {
    it('should determine archive action when confidence below threshold', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          low_importance: 0.5,
          medium_importance: 0.7,
          high_importance: 0.9,
        },
        defaultArchiveThreshold: 'low_importance',
        actionDetermination: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: false,
          applyCustomActions: false,
        },
      });
      const aiResult: FinalClassification = {
        primary_category: 'social',
        secondary_categories: [],
        confidence: 0.3, // Below low_importance threshold of 0.5
        reasoning: 'Low confidence classification',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.actionReasoning).toContain('below threshold');
    });

    it('should NOT archive when confidence above threshold', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          low_importance: 0.5,
          medium_importance: 0.7,
          high_importance: 0.9,
        },
        defaultArchiveThreshold: 'low_importance',
        actionDetermination: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: false,
          applyCustomActions: false,
        },
      });
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable'],
        confidence: 0.85, // Above threshold
        reasoning: 'High confidence classification',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.determinedActions).not.toContain('archive');
    });

    it('should mark as read when archiving if configured', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          low_importance: 0.5,
          medium_importance: 0.7,
          high_importance: 0.9,
        },
        defaultArchiveThreshold: 'low_importance',
        actionDetermination: {
          archiveIfBelowThreshold: true,
          markAsReadIfArchived: true,
          applyCustomActions: false,
        },
      });
      const aiResult: FinalClassification = {
        primary_category: 'social',
        secondary_categories: [],
        confidence: 0.3, // Below threshold
        reasoning: 'Low confidence classification',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.determinedActions).toContain('archive');
      expect(result.determinedActions).toContain('mark_as_read');
    });

    it('should apply custom actions based on category', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        actionDetermination: {
          archiveIfBelowThreshold: false,
          markAsReadIfArchived: false,
          applyCustomActions: true,
        },
        categoryActions: {
          financial: ['apply_label:important', 'star'],
          actionable: ['apply_label:todo'],
        },
      });
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable'],
        confidence: 0.85,
        reasoning: 'High confidence multi-label',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.determinedActions).toContain('apply_label:important');
      expect(result.determinedActions).toContain('star');
      expect(result.determinedActions).toContain('apply_label:todo');
    });
  });

  describe('Explainability Trace', () => {
    it('should generate complete explainability trace', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable'],
        confidence: 0.85,
        reasoning: 'High confidence financial email',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.explainabilityTrace).toBeDefined();
      expect(result.explainabilityTrace.aiClassificationInput).toEqual(aiResult);
      expect(result.explainabilityTrace.labelAssignmentRationale).toBeDefined();
      expect(result.explainabilityTrace.actionDeterminationRationale).toBeDefined();
      expect(result.explainabilityTrace.processingSteps).toBeInstanceOf(Array);
      expect(result.explainabilityTrace.processingSteps.length).toBeGreaterThan(0);
    });

    it('should track label filtering decisions in explainability', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        labelAssignmentRules: {
          maxLabels: 2,
          minSecondaryConfidence: 0.6,
          allowedCombinations: ['financial+actionable'],
        },
      });
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable', 'travel', 'social'],
        confidence: 0.85,
        reasoning: 'Multi-label classification',
        category_scores: {
          financial: 15,
          actionable: 12,
          travel: 5,
          social: 3,
        },
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.explainabilityTrace.filteredLabels).toBeDefined();
      expect(result.explainabilityTrace.filteredLabels?.length).toBeGreaterThan(0);
      expect(result.explainabilityTrace.labelAssignmentRationale).toContain('filtered');
    });

    it('should track archive threshold evaluation in explainability', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig({
        archiveThresholds: {
          low_importance: 0.5,
          medium_importance: 0.7,
          high_importance: 0.9,
        },
        defaultArchiveThreshold: 'low_importance',
      });
      const aiResult: FinalClassification = {
        primary_category: 'social',
        secondary_categories: [],
        confidence: 0.3,
        reasoning: 'Low confidence',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.explainabilityTrace.thresholdEvaluation).toBeDefined();
      expect(result.explainabilityTrace.thresholdEvaluation?.thresholdUsed).toBe(0.5);
      expect(result.explainabilityTrace.thresholdEvaluation?.confidenceScore).toBe(0.3);
      expect(result.explainabilityTrace.thresholdEvaluation?.belowThreshold).toBe(true);
    });
  });

  describe('Edge Cases', () => {
    it('should handle unclassified category gracefully', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'unclassified',
        secondary_categories: [],
        confidence: 0.5,
        reasoning: 'Could not determine category',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.assignedLabels.primary).toBe('unclassified');
      expect(result.determinedActions).toBeDefined();
    });

    it('should handle missing category_scores gracefully', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['actionable'],
        confidence: 0.85,
        reasoning: 'No category scores provided',
        // category_scores is undefined
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.assignedLabels.primary).toBe('financial');
      expect(result.assignedLabels.secondary).toEqual(['actionable']);
    });

    it('should handle empty secondary categories', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: [],
        confidence: 0.85,
        reasoning: 'Single label classification',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.assignedLabels.primary).toBe('financial');
      expect(result.assignedLabels.secondary).toEqual([]);
    });

    it('should handle missing config properties with defaults', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = {
        archiveThresholds: {
          low_importance: 0.3,
          medium_importance: 0.5,
          high_importance: 0.7,
        },
        defaultArchiveThreshold: 'low_importance',
      } as FinalDecisionConfig;
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: [],
        confidence: 0.85,
        reasoning: 'Test with minimal config',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.assignedLabels.primary).toBe('financial');
      expect(result.determinedActions).toBeDefined();
    });
  });

  describe('Performance and Metrics', () => {
    it('should track processing duration', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: [],
        confidence: 0.85,
        reasoning: 'Test performance tracking',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.processingDurationMs).toBeGreaterThanOrEqual(0);
      expect(typeof result.processingDurationMs).toBe('number');
    });

    it('should track validation errors', async () => {
      const email = createMockEmail();
      const session = createMockSession();
      const config = createMockConfig();
      const aiResult: FinalClassification = {
        primary_category: 'financial',
        secondary_categories: ['invalid_category', 'actionable'],
        confidence: 0.85,
        reasoning: 'Test with invalid category',
      };

      const result = await finalDecisionStage(email, session, aiResult, config);

      expect(result.validationErrors).toBeDefined();
      expect(Array.isArray(result.validationErrors)).toBe(true);
    });
  });
});

