     1→/**
     2→ * Final Decision Stage
     3→ *
     4→ * Stage 9 of the EmailCategorizer pipeline. Assigns final labels and determines actions based on
     5→ * AI classification results, confidence thresholds, and label assignment rules.
     6→ *
     7→ * This stage is responsible for:
     8→ * - Assigning final primary and secondary category labels
     9→ * - Filtering secondary labels based on confidence and combination rules
    10→ * - Determining actions (archive, mark as read, custom category actions)
    11→ * - Evaluating archive thresholds based on confidence scores
    12→ * - Generating complete explainability traces with decision rationale
    13→ */
    14→
    15→import { EmailMessage, ClassificationSession } from '../types';
    16→import { FinalClassification } from './ai-classification';
    17→
    18→// Configuration interface for final decision
    19→export interface FinalDecisionConfig {
    20→  archiveThresholds: {
    21→    low_importance: number;
    22→    medium_importance: number;
    23→    high_importance: number;
    24→  };
    25→  defaultArchiveThreshold: 'low_importance' | 'medium_importance' | 'high_importance';
    26→  labelAssignmentRules?: {
    27→    maxLabels: number;
    28→    minSecondaryConfidence: number;
    29→    allowedCombinations: string[];
    30→  };
    31→  actionDetermination?: {
    32→    archiveIfBelowThreshold: boolean;
    33→    markAsReadIfArchived: boolean;
    34→    applyCustomActions: boolean;
    35→  };
    36→  categoryActions?: Record<string, string[]>;
    37→}
    38→
    39→// Assigned labels result
    40→export interface AssignedLabels {
    41→  primary: string;
    42→  secondary: string[];
    43→}
    44→
    45→// Threshold evaluation details
    46→export interface ThresholdEvaluation {
    47→  thresholdType: string;
    48→  thresholdUsed: number;
    49→  confidenceScore: number;
    50→  belowThreshold: boolean;
    51→  evaluationReason: string;
    52→}
    53→
    54→// Filtered label tracking
    55→export interface FilteredLabel {
    56→  category: string;
    57→  filterReason: string;
    58→  score?: number;
    59→}
    60→
    61→// Complete explainability trace for the final decision stage
    62→export interface FinalDecisionExplainabilityTrace {
    63→  aiClassificationInput: FinalClassification;
    64→  labelAssignmentRationale: string;
    65→  actionDeterminationRationale: string;
    66→  thresholdEvaluation?: ThresholdEvaluation;
    67→  filteredLabels?: FilteredLabel[];
    68→  processingSteps: string[];
    69→}
    70→
    71→// Complete stage result interface
    72→export interface FinalDecisionResult {
    73→  assignedLabels: AssignedLabels;
    74→  determinedActions: string[];
    75→  actionReasoning: string;
    76→  processingDurationMs: number;
    77→  validationErrors: string[];
    78→  explainabilityTrace: FinalDecisionExplainabilityTrace;
    79→}
    80→
    81→/**
    82→ * Final Decision Stage Implementation
    83→ *
    84→ * Assigns final labels and determines actions based on AI classification results
    85→ * and configuration rules, with complete explainability traces.
    86→ */
    87→export async function finalDecisionStage(
    88→  email: EmailMessage,
    89→  session: ClassificationSession,
    90→  aiClassificationResult: FinalClassification,
    91→  config: FinalDecisionConfig
    92→): Promise<FinalDecisionResult> {
    93→  const startTime = Date.now();
    94→  const validationErrors: string[] = [];
    95→  const processingSteps: string[] = [];
    96→
    97→  // Validate inputs
    98→  validateInputs(email, session, aiClassificationResult, config);
    99→  processingSteps.push('Input validation completed');
   100→
   101→  // Assign labels based on AI classification and rules
   102→  const { assignedLabels, filteredLabels, labelRationale } = assignLabels(
   103→    aiClassificationResult,
   104→    config,
   105→    validationErrors,
   106→    processingSteps
   107→  );
   108→  processingSteps.push(
   109→    `Labels assigned: primary=${assignedLabels.primary}, secondary=[${assignedLabels.secondary.join(', ')}]`
   110→  );
   111→
   112→  // Determine actions based on confidence thresholds and category rules
   113→  const { determinedActions, actionReasoning, thresholdEvaluation } = determineActions(
   114→    assignedLabels,
   115→    aiClassificationResult,
   116→    config,
   117→    processingSteps
   118→  );
   119→  processingSteps.push(`Actions determined: [${determinedActions.join(', ')}]`);
   120→
   121→  // Build explainability trace
   122→  const explainabilityTrace: FinalDecisionExplainabilityTrace = {
   123→    aiClassificationInput: aiClassificationResult,
   124→    labelAssignmentRationale: labelRationale,
   125→    actionDeterminationRationale: actionReasoning,
   126→    thresholdEvaluation,
   127→    filteredLabels,
   128→    processingSteps,
   129→  };
   130→
   131→  return {
   132→    assignedLabels,
   133→    determinedActions,
   134→    actionReasoning,
   135→    processingDurationMs: Date.now() - startTime,
   136→    validationErrors,
   137→    explainabilityTrace,
   138→  };
   139→}
   140→
   141→/**
   142→ * Validate input parameters
   143→ */
   144→function validateInputs(
   145→  email: EmailMessage,
   146→  session: ClassificationSession,
   147→  aiClassificationResult: FinalClassification,
   148→  config: FinalDecisionConfig
   149→): void {
   150→  if (!email || (!email.id && !('gmail_id' in email))) {
   151→    throw new Error('Invalid email input: id or gmail_id is required');
   152→  }
   153→
   154→  if (!session || (!session.id && !('session_id' in session))) {
   155→    throw new Error('Invalid session input: id or session_id is required');
   156→  }
   157→
   158→  if (!aiClassificationResult || typeof aiClassificationResult !== 'object') {
   159→    throw new Error('Invalid AI classification result: object required');
   160→  }
   161→
   162→  if (!aiClassificationResult.primary_category || typeof aiClassificationResult.primary_category !== 'string') {
   163→    throw new Error('Invalid AI classification: primary_category is required');
   164→  }
   165→
   166→  if (!config) {
   167→    throw new Error('Configuration is required');
   168→  }
   169→
   170→  if (!config.archiveThresholds || typeof config.archiveThresholds !== 'object') {
   171→    throw new Error('Invalid configuration: archiveThresholds are required');
   172→  }
   173→}
   174→
   175→/**
   176→ * Assign labels based on AI classification and label assignment rules
   177→ */
   178→function assignLabels(
   179→  aiClassificationResult: FinalClassification,
   180→  config: FinalDecisionConfig,
   181→  validationErrors: string[],
   182→  processingSteps: string[]
   183→): {
   184→  assignedLabels: AssignedLabels;
   185→  filteredLabels: FilteredLabel[];
   186→  labelRationale: string;
   187→} {
   188→  const primaryCategory = aiClassificationResult.primary_category;
   189→  let secondaryCategories = aiClassificationResult.secondary_categories || [];
   190→  const filteredLabels: FilteredLabel[] = [];
   191→
   192→  processingSteps.push(`Initial labels: primary=${primaryCategory}, secondary=[${secondaryCategories.join(', ')}]`);
   193→
   194→  // Apply label assignment rules if configured
   195→  if (config.labelAssignmentRules) {
   196→    const rules = config.labelAssignmentRules;
   197→
   198→    // Filter by confidence threshold if category_scores are available
   199→    if (aiClassificationResult.category_scores && rules.minSecondaryConfidence) {
   200→      const primaryScore = aiClassificationResult.category_scores[primaryCategory] || 0;
   201→
   202→      secondaryCategories = secondaryCategories.filter((category) => {
   203→        const categoryScore = aiClassificationResult.category_scores![category] || 0;
   204→        const relativeConfidence = primaryScore > 0 ? categoryScore / primaryScore : 0;
   205→
   206→        if (relativeConfidence < rules.minSecondaryConfidence) {
   207→          filteredLabels.push({
   208→            category,
   209→            filterReason: `Relative confidence ${relativeConfidence.toFixed(2)} below threshold ${rules.minSecondaryConfidence}`,
   210→            score: categoryScore,
   211→          });
   212→          processingSteps.push(
   213→            `Filtered ${category}: confidence too low (${relativeConfidence.toFixed(2)} < ${rules.minSecondaryConfidence})`
   214→          );
   215→          return false;
   216→        }
   217→
   218→        return true;
   219→      });
   220→    }
   221→
