   115→/**
   116→ * AI Classification Stage Implementation
   117→ *
   118→ * Combines rule-based candidate scores with AI-extracted features to make final
   119→ * multi-label classification decisions, with intelligent skip handling for
   120→ * high-confidence scenarios.
   121→ */
   122→export async function aiClassificationStage(
   123→  email: EmailMessage,
   124→  session: ClassificationSession,
   125→  candidateCategories: Record<string, number>,
   126→  extractedFeatures: FeatureExtractionData,
   127→  config: AIClassificationConfig
   128→): Promise<AIClassificationResult> {
   129→  const startTime = Date.now();
   130→  let retryCount = 0;
   131→  let apiCallCount = 0;
   132→  let tokenUsage = 0;
   133→  const validationErrors: string[] = [];
   134→  const processingSteps: string[] = [];
   135→
   136→  // Validate inputs
   137→  validateInputs(email, session, candidateCategories, extractedFeatures, config);
   138→  processingSteps.push('Input validation completed');
   139→
   140→  // Calculate enhanced scores by applying feature confidence boosts
   141→  const enhancementCalculations: EnhancementCalculation[] = [];
   142→  const enhancedScores = calculateEnhancedScores(
   143→    candidateCategories,
   144→    extractedFeatures,
   145→    enhancementCalculations,
   146→    validationErrors
   147→  );
   148→  processingSteps.push(`Enhanced scores calculated for ${Object.keys(enhancedScores).length} categories`);
   149→
   150→  // Evaluate skip conditions
   151→  const aiRoutingDecision = evaluateSkipConditions(enhancedScores, extractedFeatures, config);
   152→  processingSteps.push(`Skip conditions evaluated: ${aiRoutingDecision.reason}`);
   153→
   154→  // Initialize explainability trace
   155→  const explainabilityTrace: AIClassificationExplainabilityTrace = {
   156→    candidateScoresInput: { ...candidateCategories },
   157→    extractedFeaturesInput: { ...extractedFeatures },
   158→    enhancementCalculations,
   159→    aiRoutingDecision,
   160→    finalDecisionRationale: '',
   161→    processingSteps,
   162→  };
   163→
   164→  // Handle skip scenarios
   165→  if (!aiRoutingDecision.routedToAI) {
   166→    const finalClassification = createDirectClassification(enhancedScores, aiRoutingDecision.reason);
   167→    explainabilityTrace.finalDecisionRationale = `Direct classification based on ${aiRoutingDecision.reason}`;
   168→
   169→    return {
   170→      finalClassification,
   171→      enhancedScores,
   172→      aiInvoked: false,
   173→      skipped: true,
   174→      skipReason: aiRoutingDecision.reason,
   175→      processingDurationMs: Date.now() - startTime,
   176→      tokenUsage: 0,
   177→      apiCallCount: 0,
   178→      retryCount: 0,
   179→      validationErrors,
   180→      explainabilityTrace,
   181→    };
   182→  }
   183→
   184→  // Proceed with AI classification
   185→  processingSteps.push('Proceeding with AI classification');
   186→
   187→  // Initialize OpenAI client
   188→  const openai = new OpenAI({
   189→    apiKey: config.openai.apiKey,
   190→  });
   191→
   192→  // Retry loop for AI API calls
   193→  let lastError: Error | null = null;
   194→
   195→  while (retryCount < config.retryPolicy.maxRetries) {
   196→    try {
   197→      apiCallCount++;
   198→      processingSteps.push(`AI API call attempt ${apiCallCount}`);
   199→
   200→      // Prepare prompts with enhanced scores and features
   201→      const systemPrompt = config.prompts.systemPrompt.join('\n');
   202→      const userPrompt = interpolateClassificationPrompt(
   203→        config.prompts.userPrompt,
   204→        email,
   205→        enhancedScores,
   206→        extractedFeatures
   207→      );
   208→
   209→      // Prepare response format based on configuration
   210→      const responseFormat =
   211→        config.openai.responseFormat === 'json_schema'
   212→          ? {
   213→            type: 'json_schema' as const,
   214→            json_schema: {
   215→              name: config.classificationSchema.name || 'final_classification',
   216→              description: config.classificationSchema.description || 'Final multi-label email classification',
   217→              schema: config.classificationSchema.schema,
   218→              strict: config.classificationSchema.strict ?? true,
   219→            },
   220→          }
   221→          : { type: 'json_object' as const }; // Backward compatibility
   222→
   223→      // Call OpenAI API
   224→      const response = await openai.chat.completions.create({
   225→        model: config.openai.model,
   226→        temperature: config.openai.temperature,
   227→        response_format: responseFormat,
   228→        messages: [
   229→          { role: 'system', content: systemPrompt },
   230→          { role: 'user', content: userPrompt },
   231→        ],
   232→      });
   233→
   234→      // Parse and validate response
   235→      const rawContent = response.choices[0].message.content;
   236→      if (!rawContent) {
   237→        throw new Error('Empty response from OpenAI');
   238→      }
   239→
   240→      let finalClassification: FinalClassification;
   241→      try {
   242→        finalClassification = JSON.parse(rawContent);
   243→      } catch {
   244→        throw new Error('Invalid JSON response from OpenAI');
   245→      }
   246→
   247→      // Track API usage
   248→      tokenUsage = response.usage?.total_tokens || 0;
   249→      explainabilityTrace.apiUsage = {
   250→        totalTokens: response.usage?.total_tokens || 0,
   251→        promptTokens: response.usage?.prompt_tokens,
   252→        completionTokens: response.usage?.completion_tokens,
   253→      };
   254→
   255→      // Validate AI response structure
   256→      validateAIResponse(finalClassification as unknown as Record<string, unknown>);
   257→
   258→      explainabilityTrace.finalDecisionRationale = `AI classification completed: ${finalClassification.reasoning}`;
   259→      processingSteps.push('AI classification successful');
   260→
   261→      // Success - return result
   262→      return {
   263→        finalClassification,
   264→        enhancedScores,
   265→        aiInvoked: true,
   266→        skipped: false,
   267→        processingDurationMs: Date.now() - startTime,
   268→        tokenUsage,
   269→        apiCallCount,
   270→        retryCount,
   271→        validationErrors,
   272→        explainabilityTrace,
   273→      };
   274→    } catch (error) {
   275→      lastError = error as Error;
   276→      retryCount++;
   277→      processingSteps.push(`AI API call failed (attempt ${apiCallCount}): ${lastError.message}`);
   278→
   279→      if (retryCount < config.retryPolicy.maxRetries) {
   280→        // Wait before retry with exponential backoff
   281→        const backoffMs = config.retryPolicy.backoffMs * Math.pow(2, retryCount - 1);
   282→        await new Promise((resolve) => setTimeout(resolve, backoffMs));
   283→        processingSteps.push(`Retrying after ${backoffMs}ms backoff`);
   284→      }
   285→    }
   286→  }
   287→
   288→  // All retries exhausted
   289→  throw new Error(`AI classification failed after ${config.retryPolicy.maxRetries} retries: ${lastError?.message}`);
   290→}
