   292→/**
   293→ * Validate input parameters
   294→ */
   295→function validateInputs(
   296→  email: EmailMessage,
   297→  session: ClassificationSession,
   298→  candidateCategories: Record<string, number>,
   299→  extractedFeatures: FeatureExtractionData,
   300→  config: AIClassificationConfig
   301→): void {
   302→  if (!email || (!email.id && !('gmail_id' in email))) {
   303→    throw new Error('Invalid email input: id or gmail_id is required');
   304→  }
   305→
   306→  if (!session || (!session.id && !('session_id' in session))) {
   307→    throw new Error('Invalid session input: id or session_id is required');
   308→  }
   309→
   310→  if (!candidateCategories || typeof candidateCategories !== 'object') {
   311→    throw new Error('Invalid candidate categories: object with numeric scores required');
   312→  }
   313→
   314→  if (!extractedFeatures || typeof extractedFeatures !== 'object') {
   315→    throw new Error('Invalid extracted features: feature extraction data required');
   316→  }
   317→
   318→  if (!config) {
   319→    throw new Error('Configuration is required');
   320→  }
   321→
   322→  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
   323→    throw new Error('Invalid configuration: OpenAI API key is required');
   324→  }
   325→
   326→  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
   327→    throw new Error('Invalid configuration: system and user prompts are required');
   328→  }
   329→
   330→  if (!config.classificationSchema?.schema) {
   331→    throw new Error('Invalid configuration: classification schema is required');
   332→  }
   333→}
   334→
   335→/**
   336→ * Calculate enhanced scores by applying AI feature confidence boosts
   337→ */
   338→function calculateEnhancedScores(
   339→  candidateCategories: Record<string, number>,
   340→  extractedFeatures: FeatureExtractionData,
   341→  enhancementCalculations: EnhancementCalculation[],
   342→  validationErrors: string[]
   343→): Record<string, number> {
   344→  const enhancedScores: Record<string, number> = {};
   345→
   346→  // Validate extracted features format
   347→  if (!extractedFeatures.semantic_intent || !extractedFeatures.category_enhancements) {
   348→    validationErrors.push('Invalid extracted features format');
   349→    // Fallback to original scores without enhancement
   350→    return { ...candidateCategories };
   351→  }
   352→
   353→  for (const [category, originalScore] of Object.entries(candidateCategories)) {
   354→    let enhancedScore = originalScore;
   355→    let confidenceBoost = 0;
   356→    let boostReason = 'No feature enhancement';
   357→
   358→    // Apply AI feature enhancement if available
   359→    const categoryEnhancement = extractedFeatures.category_enhancements?.[category];
   360→    if (categoryEnhancement) {
   361→      confidenceBoost = categoryEnhancement.confidence_boost || 0;
   362→
   363→      // Apply positive boosts only when category applies, but apply negative boosts regardless
   364→      if (categoryEnhancement.applies || confidenceBoost < 0) {
   365→        enhancedScore = originalScore + originalScore * confidenceBoost;
   366→        boostReason = `Applied ${confidenceBoost > 0 ? 'positive' : 'negative'} confidence boost based on AI features`;
   367→      }
   368→    }
   369→
   370→    enhancedScores[category] = enhancedScore;
   371→
   372→    // Track enhancement calculation for explainability
   373→    enhancementCalculations.push({
   374→      category,
   375→      originalScore,
   376→      confidenceBoost,
   377→      enhancedScore,
   378→      boostReason,
   379→    });
   380→  }
   381→
   382→  return enhancedScores;
   383→}
   384→
   385→/**
   386→ * Evaluate skip conditions to determine if AI classification should be bypassed
   387→ */
   388→function evaluateSkipConditions(
   389→  enhancedScores: Record<string, number>,
   390→  extractedFeatures: FeatureExtractionData,
   391→  config: AIClassificationConfig
   392→): AIRoutingDecision {
   393→  const skipConditionsEvaluated: string[] = [];
   394→
   395→  // Find highest scoring category
   396→  const maxScore = Math.max(...Object.values(enhancedScores));
   397→
   398→  // Check for hard assertion condition first (highest priority)
   399→  if (config.skipConditions.skipReasons.includes('hard_assertion')) {
   400→    skipConditionsEvaluated.push('hard_assertion');
   401→    if ((extractedFeatures as unknown as Record<string, unknown>).hard_assertion_detected) {
   402→      return {
   403→        routedToAI: false,
   404→        reason: 'hard_assertion',
   405→        skipConditionsEvaluated,
   406→        decisionRationale: 'Hard assertion detected in earlier pipeline stage',
   407→      };
   408→    }
   409→  }
   410→
   411→  // Check high confidence threshold
   412→  skipConditionsEvaluated.push('high_confidence_threshold');
   413→  if (maxScore >= config.skipConditions.highConfidenceThreshold) {
   414→    return {
   415→      routedToAI: false,
   416→      reason: 'high_confidence',
   417→      confidenceScore: maxScore,
   418→      threshold: config.skipConditions.highConfidenceThreshold,
   419→      skipConditionsEvaluated,
   420→      decisionRationale: `Highest category score (${maxScore}) exceeds high confidence threshold (${config.skipConditions.highConfidenceThreshold})`,
   421→    };
   422→  }
   423→
   424→  // Default: route to AI
   425→  return {
   426→    routedToAI: true,
   427→    reason: 'requires_ai_classification',
   428→    skipConditionsEvaluated,
   429→    decisionRationale: `Confidence scores require AI classification (max: ${maxScore}, threshold: ${config.skipConditions.highConfidenceThreshold})`,
   430→  };
   431→}
   432→
   433→/**
   434→ * Create direct classification result when AI is skipped
   435→ */
   436→function createDirectClassification(enhancedScores: Record<string, number>, skipReason: string): FinalClassification {
   437→  // Sort categories by score descending
   438→  const sortedCategories = Object.entries(enhancedScores)
   439→    .sort(([, a], [, b]) => b - a)
   440→    .filter(([, score]) => score > 0);
   441→
   442→  if (sortedCategories.length === 0) {
