     2→import { EmailMessage, HardAssertionResult } from '../types';
     3→import { extractDomainFromEmail, findMatchingDomain, normalizeEmail } from '../utils/email-utils';
     4→import { ClassificationContext } from './types';
     5→
     6→/**
     7→ * Hard Assertions Stage
     8→ *
     9→ * Implements HIGH_CONFIDENCE_FLOOR logic per SCORING_LOGIC.md "Hard Assertions" section.
    10→ * Single match can directly elevate a top-level category to high confidence baseline.
    11→ *
    12→ * Logic:
    13→ * - If any hard assertion matches: category_score = max(category_score, HIGH_CONFIDENCE_FLOOR)
    14→ * - Mark flag: hard_assertion = true
    15→ * - Where HIGH_CONFIDENCE_FLOOR = confidence_thresholds.high_confidence
    16→ */
    17→
    18→export interface HardAssertionConfig {
    19→  from_domains_ref?: {
    20→    source_group: string;
    21→    confidence: 'high' | 'medium';
    22→  };
    23→  subject_prefixes?: string[];
    24→  from_addresses?: string[];
    25→}
    26→
    27→export interface HardAssertionStageConfig {
    28→  confidenceThresholds: {
    29→    high_confidence: number;
    30→    medium_confidence: number;
    31→    low_confidence: number;
    32→  };
    33→  categorySignals: Record<string, { hard_assertions?: HardAssertionConfig }>;
    34→  domainLookup: Record<
    35→    string,
    36→    {
    37→      high_confidence: Array<{ domain: string; type?: string }>;
    38→      medium_confidence: Array<{ domain: string; type?: string }>;
    39→      low_confidence: Array<{ domain: string; type?: string }>;
    40→    }
    41→  >;
    42→}
    43→
    44→export interface HardAssertionStageResult {
    45→  categoriesWithHardAssertions: string[];
    46→  assertionResults: HardAssertionResult[];
    47→  updatedScores: Record<string, number>;
    48→  processingDurationMs: number;
    49→}
    50→
    51→/**
    52→ * Executes hard assertions stage of email classification
    53→ *
    54→ * @param email The email message to classify
    55→ * @param context Current classification context with category scores
    56→ * @param config Configuration containing category signals and thresholds
    57→ * @returns Hard assertion results and updated scores
    58→ */
    59→export function executeHardAssertions(
    60→  email: EmailMessage,
    61→  context: ClassificationContext,
    62→  config: HardAssertionStageConfig
    63→): HardAssertionStageResult {
    64→  const startTime = Date.now();
    65→  const categoriesWithHardAssertions: string[] = [];
    66→  const assertionResults: HardAssertionResult[] = [];
    67→  const updatedScores: Record<string, number> = { ...context.categoryScores };
    68→
    69→  const HIGH_CONFIDENCE_FLOOR = config.confidenceThresholds.high_confidence;
    70→
    71→  // Process each category that has hard assertions configured
    72→  for (const [categoryName, categoryConfig] of Object.entries(config.categorySignals)) {
    73→    if (!categoryConfig.hard_assertions) {
    74→      continue;
    75→    }
    76→
    77→    const hardAssertions = categoryConfig.hard_assertions;
    78→    let categoryHadAssertion = false;
    79→
    80→    // Check from_domains_ref (domain-based hard assertions)
    81→    if (hardAssertions.from_domains_ref) {
    82→      const { source_group, confidence } = hardAssertions.from_domains_ref;
    83→
    84→      // Only treat as hard assertion if confidence is 'high'
    85→      if (confidence === 'high') {
    86→        const domainGroup = config.domainLookup[source_group];
    87→        if (domainGroup) {
    88→          const emailDomain = extractDomainFromEmail(email.from.email);
    89→          const matchedDomain = findMatchingDomain(emailDomain, domainGroup, 'high');
    90→
    91→          if (matchedDomain) {
    92→            assertionResults.push({
    93→              category: categoryName,
    94→              triggered: true,
    95→              assertionType: 'from_domain',
    96→              matchedValue: matchedDomain.domain,
    97→              confidence: 'HIGH_CONFIDENCE',
    98→              sourceGroup: source_group,
    99→              reason: `Email from domain '${emailDomain}' matches high-confidence domain '${matchedDomain.domain}' in group '${source_group}'`,
   100→            });
   101→            categoryHadAssertion = true;
   102→          }
   103→        }
   104→      }
   105→    }
   106→
   107→    // Check subject_prefixes
   108→    if (hardAssertions.subject_prefixes) {
   109→      const subject = email.subject.toLowerCase();
   110→
   111→      for (const prefix of hardAssertions.subject_prefixes) {
   112→        if (subject.startsWith(prefix.toLowerCase())) {
   113→          assertionResults.push({
   114→            category: categoryName,
   115→            triggered: true,
   116→            assertionType: 'subject_prefix',
   117→            matchedValue: prefix,
   118→            confidence: 'HIGH_CONFIDENCE',
   119→            reason: `Subject '${email.subject}' starts with hard assertion prefix '${prefix}'`,
   120→          });
   121→          categoryHadAssertion = true;
   122→          break; // First match is sufficient
   123→        }
   124→      }
   125→    }
   126→
   127→    // Check from_addresses (exact email address matches)
   128→    if (hardAssertions.from_addresses) {
   129→      const fromEmail = normalizeEmail(email.from.email);
   130→
   131→      for (const address of hardAssertions.from_addresses) {
   132→        if (fromEmail === normalizeEmail(address)) {
   133→          assertionResults.push({
   134→            category: categoryName,
   135→            triggered: true,
   136→            assertionType: 'from_address',
   137→            matchedValue: address,
   138→            confidence: 'HIGH_CONFIDENCE',
   139→            reason: `Email from address '${fromEmail}' matches hard assertion address '${address}'`,
   140→          });
   141→          categoryHadAssertion = true;
   142→          break; // First match is sufficient
   143→        }
   144→      }
   145→    }
   146→
