   148→    if (categoryHadAssertion) {
   149→      const currentScore = updatedScores[categoryName] || 0;
   150→      const newScore = Math.max(currentScore, HIGH_CONFIDENCE_FLOOR);
   151→      updatedScores[categoryName] = newScore;
   152→      categoriesWithHardAssertions.push(categoryName);
   153→    }
   154→  }
   155→
   156→  const processingDurationMs = Date.now() - startTime;
   157→
   158→  // Update context tracking
   159→  context.stageTimings['hard_assertions'] = processingDurationMs;
   160→  context.configurationRefs['hard_assertions'] = 'category_signals.*.hard_assertions';
   161→  context.hardAssertionsApplied = categoriesWithHardAssertions;
